import{_ as o,o as t,c,a2 as a}from"./chunks/framework.DvFsUg-r.js";const h=JSON.parse('{"title":"LLM 강의 임포트 — Research (Phase 0)","description":"","frontmatter":{"title":"LLM 강의 임포트 — Research (Phase 0)","feature_id":"012","created":"2026-06-03 15:08 (KST)","date":"2026-06-03T00:00:00.000Z"},"headers":[],"relativePath":"specs/012-llm-course-import/research.md","filePath":"specs/012-llm-course-import/research.md","lastUpdated":null}'),r={name:"specs/012-llm-course-import/research.md"};function d(s,e,i,l,n,m){return t(),c("div",null,[...e[0]||(e[0]=[a('<h1 id="research-llm-main-→-vitepress-llm-임포트" tabindex="-1">Research: llm-main → VitePress <code>/llm/</code> 임포트 <a class="header-anchor" href="#research-llm-main-→-vitepress-llm-임포트" aria-label="Permalink to &quot;Research: llm-main → VitePress `/llm/` 임포트&quot;">​</a></h1><p>스펙의 미해결 지점과 Technical Context 의 결정 사항을 해소한 결과. 각 항목: <strong>Decision / Rationale / Alternatives</strong>. 선례는 <a href="./../008-hexo-blog-import/research">008-hexo-blog-import</a>.</p><h2 id="r1-구현-언어-—-node-esm-단일-스크립트" tabindex="-1">R1. 구현 언어 — Node ESM 단일 스크립트 <a class="header-anchor" href="#r1-구현-언어-—-node-esm-단일-스크립트" aria-label="Permalink to &quot;R1. 구현 언어 — Node ESM 단일 스크립트&quot;">​</a></h2><ul><li><strong>Decision</strong>: 임포터를 <strong>Node ESM 스크립트</strong>(<code>scripts/import-llm-course.mjs</code>, Node 내장 모듈만)로 구현한다. 선례(008)와 동일. 얇은 <code>.ps1</code>/<code>.sh</code> 래퍼 제공.</li><li><strong>Rationale</strong>: 제목 도출·이미지 경로 재작성·예제 인라인·<code>.mts</code> 사이드바 생성 으로 이뤄진 텍스트 변환 파이프라인이다. 블로그가 이미 Node(VitePress) 툴체인을 쓰므로 추가 런타임 없음. 산출물(사이드바)이 <code>.mts</code> 라 Node 생성이 자연스럽다.</li><li><strong>Alternatives</strong>: PS+Bash 페어(복잡 변환에 중복·버그 위험) → 기각. npm 의존 추가(gray-matter 등) → 의존 0 원칙 위해 최소 파서 자체 구현.</li></ul><h2 id="r2-이미지-경로-불일치-해소-app-static-→-static" tabindex="-1">R2. 이미지 경로 불일치 해소 (<code>app/static/</code> → <code>static/</code>) <a class="header-anchor" href="#r2-이미지-경로-불일치-해소-app-static-→-static" aria-label="Permalink to &quot;R2. 이미지 경로 불일치 해소 (`app/static/` → `static/`)&quot;">​</a></h2><ul><li><strong>Decision</strong>: 본문의 모든 <code>![](app/static/&lt;file&gt;)</code> 참조에서 선행 <code>app/</code> 를 제거해 실제 위치 <code>static/&lt;file&gt;</code> 로 해석한다. 해당 파일을 <code>blog/llm/assets/</code> 로 복사하고 본문 링크를 <code>./assets/&lt;file&gt;</code> 상대 링크로 재작성한다.</li><li><strong>Rationale</strong>: 원본은 <code>static/</code> 에 파일이 있는데 본문은 존재하지 않는 <code>app/</code> 접두로 가리킨다(확인됨: <code>static/101_1.png</code> 존재, <code>app/static/</code> 부재). 접두 제거 단일 규칙으로 전부 해소된다. 파일명이 이미 강의번호로 네임스페이스(<code>101_1</code>, <code>103_2</code>)되어 단일 <code>assets/</code> 폴더로 충돌 없이 모은다.</li><li><strong>Alternatives</strong>: 글별 <code>.assets/</code> 분리(008 방식) → 파일명이 이미 네임스페이스 되어 불필요. <code>public/</code> 강제 복사 → 상대 링크면 VitePress 가 번들하므로 불필요.</li></ul><h2 id="r3-정렬·슬러그-—-강의-번호-기반-학습-순서" tabindex="-1">R3. 정렬·슬러그 — 강의 번호 기반 (학습 순서) <a class="header-anchor" href="#r3-정렬·슬러그-—-강의-번호-기반-학습-순서" aria-label="Permalink to &quot;R3. 정렬·슬러그 — 강의 번호 기반 (학습 순서)&quot;">​</a></h2><ul><li><strong>Decision</strong>: 정렬키는 <code>m(\\d+)(?:\\.(\\d+))?</code> 파싱 → <code>[major, minor]</code> 오름차순 (예: m101 &lt; m107.0 &lt; m107.1 &lt; m108.0 &lt; m135). 슬러그는 <code>.</code>→<code>-</code> 정규화 (<code>m107.0</code>→<code>m107-0</code>), 링크 <code>/llm/m107-0</code>. 사이드바·인덱스 모두 이 순서.</li><li><strong>Rationale</strong>: 강의 시리즈는 순차 학습용이므로 학습 순서(번호 오름차순)를 보존한다 — 본 저장소 &quot;최신 먼저&quot; 기본의 <strong>명시적 예외</strong>(spec FR-3, Assumptions). 슬러그의 <code>.</code> 는 VitePress 라우팅에서 확장자처럼 보일 수 있어 <code>-</code> 로 정규화.</li><li><strong>Alternatives</strong>: 최신 먼저(번호 내림차순) → 강의 흐름 역행, 기각. 파일명 그대로 <code>.0</code> 슬러그 → 라우팅 혼동 위험, 기각.</li></ul><h2 id="r4-빈-강의-처리-m124-m127-0-byte" tabindex="-1">R4. 빈 강의 처리 (m124~m127, 0-byte) <a class="header-anchor" href="#r4-빈-강의-처리-m124-m127-0-byte" aria-label="Permalink to &quot;R4. 빈 강의 처리 (m124~m127, 0-byte)&quot;">​</a></h2><ul><li><strong>Decision</strong>: 본문이 비어 있는(0-byte 또는 공백만) 강의는 <strong>임포트에서 제외</strong> 하고 리포트의 <code>skipped</code> 에 사유와 함께 집계한다. 그 강의에 대응하는 예제 <code>m*.py</code> 는 게시할 본문이 없으므로 <code>examplesOrphaned</code> 로 집계(차단 아님).</li><li><strong>Rationale</strong>: 확인 결과 <code>m124.md</code>~<code>m127.md</code> 는 0-byte 다. 본문 없는 페이지는 제목 도출이 불가능하고 독자 가치가 없다. 스킵 + 가시화가 가장 충실·저위험.</li><li><strong>Alternatives</strong>: 예제 <code>.py</code> 만으로 코드-only 페이지 생성 → 제목·맥락 없는 코드 덤프라 가치 낮음, 기각. 빈 페이지 게시 → strict 빌드/UX 저해, 기각.</li></ul><h2 id="r5-제목-도출-규칙-비균일-헤딩" tabindex="-1">R5. 제목 도출 규칙 (비균일 헤딩) <a class="header-anchor" href="#r5-제목-도출-규칙-비균일-헤딩" aria-label="Permalink to &quot;R5. 제목 도출 규칙 (비균일 헤딩)&quot;">​</a></h2><ul><li><strong>Decision</strong>: 본문 첫 헤딩 라인(<code>#</code>/<code>##</code>/<code>###</code>)에서 ① 선행 <code>#</code> 기호, ② 선행/ 내부 이모지, ③ <code>개발 블로그 #NN.</code> 류 접두, ④ 후행 공백을 제거한 텍스트를 제목으로 쓴다. 헤딩이 전혀 없으면(비-빈 강의) <code>Lesson &lt;stem&gt;</code> 폴백. 상세 규칙은 <a href="./contracts/transform-rules">contracts/transform-rules.md</a> T-title.</li><li><strong>Rationale</strong>: m101~m106 은 <code>### 💻 …</code> 섹션형, m111 은 <code>## 😮‍💨 개발 블로그 #11. …</code>, m107+ 는 정상 <code># …</code> 로 제각각이다. 정규화 + 폴백으로 모든 강의에 안정적 제목을 보장한다. 사이드바 text 는 <code>mNNN · &lt;title&gt;</code> 로 번호를 항상 노출해 학습 순서를 가시화한다.</li><li><strong>Alternatives</strong>: 파일명만 제목 사용 → 가독성 낮음, 기각. 첫 문단 추출 → 불안정, 기각.</li></ul><h2 id="r6-예제-코드-인라인-fr-6" tabindex="-1">R6. 예제 코드 인라인 (FR-6) <a class="header-anchor" href="#r6-예제-코드-인라인-fr-6" aria-label="Permalink to &quot;R6. 예제 코드 인라인 (FR-6)&quot;">​</a></h2><ul><li><strong>Decision</strong>: 각 강의 본문 <strong>말미</strong>에 매핑된 예제 <code>.py</code>(동명 stem) 내용을 <code>## 전체 예제 코드</code> 헤딩 + <code>```python</code> 펜스로 인라인한다. 본문 중간 코드 블록은 보존. 매핑 예제가 없으면 블록 생략. 매핑은 <strong>stem 1:1</strong>(<code>m107.0.py</code>↔<code>m107.0.md</code>).</li><li><strong>Rationale</strong>: 클arification(2026-06-03) 결정 — 페이지 이동 없이 강의+전체 코드를 함께 본다. stem 1:1 매핑이라 단순·예측 가능(스펙의 &quot;여럿&quot; 표현은 <code>m107.0/.1/.2</code> 가 각각 별도 강의+예제 쌍이라는 의미로 해소).</li><li><strong>Alternatives</strong>: 별도 코드 페이지/다운로드 → 이동 필요, 기각(클arification).</li></ul><h2 id="r7-프런트매터-가상-일자-fr-2" tabindex="-1">R7. 프런트매터 &amp; 가상 일자 (FR-2) <a class="header-anchor" href="#r7-프런트매터-가상-일자-fr-2" aria-label="Permalink to &quot;R7. 프런트매터 &amp; 가상 일자 (FR-2)&quot;">​</a></h2><ul><li><strong>Decision</strong>: 출력 프런트매터 = <code>title</code>, <code>created</code>(<code>YYYY-MM-DD HH:MM (KST)</code>), <code>date</code>(ISO, created 와 동일 시각), <code>editLink:false</code>, <code>lastUpdated:false</code>. <code>created</code>/<code>date</code> 는 정렬 순서 index 로 <strong>단조 증가하는 가상 시각</strong> (base 시각 + index 분). 원본에 작성시각 메타가 없어 합성한다.</li><li><strong>Rationale</strong>: CLAUDE.md 는 <code>created</code> 에 시각 포함을 요구한다. 번호 순으로 증가하는 가상 시각이면 표기·정렬이 학습 순서와 일관된다. <code>editLink/lastUpdated</code> 비활성으로 임포트 글에 부정확한 소스 편집/수정일 링크가 붙지 않게 한다.</li><li><strong>Alternatives</strong>: 원본 mtime → 전 파일 동일 시각(Oct 2025)이라 무의미, 기각. 임포트 실행일 일괄 → 강의 간 구분 없음, 기각.</li></ul><h2 id="r8-vue-mdx-빌드-안전성" tabindex="-1">R8. Vue/MDX 빌드 안전성 <a class="header-anchor" href="#r8-vue-mdx-빌드-안전성" aria-label="Permalink to &quot;R8. Vue/MDX 빌드 안전성&quot;">​</a></h2><ul><li><strong>Decision</strong>: 본문 텍스트의 <code>{{ … }}</code>(코드펜스/인라인코드 밖)와 비표준 미닫힘 <code>&lt;tag&gt;</code> 토큰을 이스케이프한다(008 R5 <code>sanitizeVue</code> 규칙 재사용). 인라인 코드/ 코드펜스 내부는 보존.</li><li><strong>Rationale</strong>: VitePress=Vue. 프롬프트 설명의 <code>{role}</code>·<code>{변수}</code> 나 정체불명 <code>&lt;Tag&gt;</code> 가 코드펜스 밖이면 컴파일 에러로 strict 빌드를 깬다(FR-7). LLM 강의는 langchain 템플릿 문법(<code>{var}</code>)을 본문 설명에 노출할 수 있어 특히 주의.</li><li><strong>Alternatives</strong>: 페이지 전체 <code>v-pre</code>/코드블록화 → 렌더 깨짐, 기각. 토큰 단위 이스케이프 채택.</li></ul><h2 id="r9-섹션-노출-형태-config-배선-fr-8" tabindex="-1">R9. 섹션 노출 형태 &amp; config 배선 (FR-8) <a class="header-anchor" href="#r9-섹션-노출-형태-config-배선-fr-8" aria-label="Permalink to &quot;R9. 섹션 노출 형태 &amp; config 배선 (FR-8)&quot;">​</a></h2><ul><li><strong>Decision</strong>: 진입 <code>index.md</code> 는 hero 없는 <strong>강의 인덱스</strong>(번호순 목록 + 짧은 소개). nav 는 기존 &quot;학습 가이드&quot; 그룹에 <code>{ text: &#39;LLM 강의&#39;, link: &#39;/llm/&#39; }</code> 추가, 사이드바는 <code>...llmSidebar</code> 스프레드. 008 <code>blog-archive</code> 배선과 동형. <code>config.mts</code> 는 SPECKIT 마커가 없으므로(현행 cowork/hermes/blog-archive 와 동일) <strong>존재 검사 기반 멱등 주입</strong>을 쓰고, 실패 시 수동 3줄 폴백을 문서화.</li><li><strong>Rationale</strong>: 강의는 순차 콘텐츠라 마케팅형 hero 보다 번호순 인덱스가 적합. 기존 섹션과 동일 패턴이라 유지보수 일관.</li><li><strong>Alternatives</strong>: 별도 최상위 nav 그룹 신설 → 메뉴 비대, &quot;학습 가이드&quot; 그룹에 편입이 자연. blog-archive 하위 편입 → 클arification 에서 전용 <code>/llm/</code> 로 확정됨.</li></ul>',20)])])}const u=o(r,[["render",d]]);export{h as __pageData,u as default};
